INSERT INTO public.blog_posts (title, slug, category, author, excerpt, published, published_at, content) VALUES
(
  'Fruktkorg Södermalm – Fruktleverans till kontoret på Söder',
  'fruktkorg-sodermalm-fruktleverans-kontoret',
  'tips',
  'Vitaminkorgen',
  'Allt om fruktkorgar och fruktleverans till kontor på Södermalm. Leveransområden, priser och hur du beställer fruktkorg till ditt företag på Söder.',
  true,
  '2026-04-15T08:00:00Z',
  E'## Fruktkorg Södermalm – Färsk frukt till ditt kontor på Söder\n\nSödermalm är ett av Stockholms mest populära kontorsområden, med allt från kreativa byråer i Hornstull till tech-startups vid Medborgarplatsen. Oavsett var på Söder ert kontor ligger levererar Vitaminkorgen **färska fruktkorgar direkt till dörren** – varje vecka.\n\n## Varför välja fruktkorg till kontoret på Södermalm?\n\nAtt erbjuda frukt på jobbet är mer än bara ett hälsosamt mellanmål. Det är en investering i medarbetarnas välmående och en signal om att ni som arbetsgivare bryr er om er personal.\n\n### Fördelarna med frukt på kontoret\n\n- **Ökad energi och fokus** – Naturligt socker från frukt ger jämn energi utan sockerkraschen\n- **Stärkt immunförsvar** – Vitaminer och antioxidanter håller medarbetarna friskare\n- **Bättre arbetsmiljö** – Gemensamma fruktpauser stärker teamkänslan\n- **Minskad sjukfrånvaro** – Hälsosamma medarbetare är produktiva medarbetare\n\n## Så fungerar fruktleverans till Södermalm\n\nVi levererar till **alla delar av Södermalm**, inklusive:\n\n- Hornstull och Långholmen\n- Medborgarplatsen och Björns Trädgård\n- Slussen och Gamla Stan (nära)\n- Mariatorget och Zinkensdamm\n- Skanstull och Hammarby Sjöstad\n- Nytorget och Vitabergsparken\n\n### Leveranstider\n\nVi levererar fruktkorgar till Södermalm **måndag till fredag**, och ni väljer själva vilken dag som passar bäst. De flesta kontor på Söder föredrar leverans på måndagar eller tisdagar så att fruktkorgen räcker hela veckan.\n\n## Våra fruktkorgar för kontor på Södermalm\n\n| Fruktkorg | Innehåll | Pris från | Passar |\n|-----------|----------|-----------|--------|\n| Original | Blandad säsongsfrukt, 4 kg | 230 kr/vecka | 5–8 personer |\n| Premium | Handplockat urval, 6 kg | 340 kr/vecka | 8–15 personer |\n| Banan | Enbart bananer, 5 kg | 199 kr/vecka | Aktiva kontor |\n\n**Alla leveranser till Södermalm är fraktfria.**\n\n## Komplettera fruktkorgen med mer\n\nMånga av våra kunder på Södermalm beställer även:\n\n- **Kaffe och te** – Färskmalet kaffe från lokala rosterier\n- **Mejeri** – Mjölk, havremjölk och yoghurt\n- **Snacks** – Nötter, müslibars och torkad frukt\n- **Läsk och dryck** – Mineralvatten och juice\n\nAllt levereras samtidigt som fruktkorgen – **en leverans, en faktura**.\n\n[Se hela vårt sortiment](/produkter)\n\n## Populära kontor vi levererar till på Södermalm\n\nVi levererar fruktkorgar till över **150 företag i Stockholm**, och Södermalm är ett av våra mest populära områden. Bland våra kunder finns:\n\n- Kreativa byråer i Hornstull\n- Tech-startups vid Medborgarplatsen\n- Advokatbyråer vid Slussen\n- Konsultfirmor vid Mariatorget\n- Arkitektkontor vid Nytorget\n\n## Testa gratis – ingen bindningstid\n\nVi erbjuder en **kostnadsfri provkorg** till alla nya kunder på Södermalm. Ingen bindningstid, inga dolda avgifter. Är ni inte nöjda behöver ni bara säga till.\n\n[Beställ en gratis provkorg](/provkorg)\n\n## Kontakta oss\n\nVill ni veta mer om fruktkorgar till ert kontor på Södermalm? Kontakta oss så hjälper vi er att hitta rätt lösning.\n\n- Ring: [010-183 98 36](tel:010-1839836)\n- E-post: [info@vitaminkorgen.se](mailto:info@vitaminkorgen.se)\n- [Begär offert](/kontakt)\n\n**Vitaminkorgen – Ert fruktbud på Södermalm sedan 2021.**'
),
(
  'Fruktpåsar till företag – Smidig frukt i portionsförpackning',
  'fruktpasar-foretag-portionsforpackning',
  'tips',
  'Vitaminkorgen',
  'Guide till fruktpåsar för företag. Så fungerar portionsförpackad frukt till kontoret – fördelar, innehåll och hur du beställer fruktpåsar till ditt företag.',
  true,
  '2026-04-14T08:00:00Z',
  E'## Fruktpåsar till företag – Portionsförpackad frukt för kontoret\n\nInte alla kontor passar för en stor fruktkorg i gemensamma utrymmen. Kanske jobbar ni hybrid, har flera våningsplan, eller vill helt enkelt att varje medarbetare får sin egen portion. Då är **fruktpåsar** det perfekta alternativet.\n\n## Vad är en fruktpåse?\n\nEn fruktpåse är en **individuell portionsförpackning med färsk frukt**, perfekt för att dela ut till medarbetare eller placera vid arbetsplatser. Varje påse innehåller en blandning av säsongens bästa frukt – tvättad, sorterad och redo att äta.\n\n### Innehåll i en typisk fruktpåse\n\n- 2–3 frukter per påse (t.ex. äpple, banan, päron eller clementin)\n- Säsongsvarierat innehåll för variation\n- Frukt av högsta kvalitet, handplockad\n\n## Varför välja fruktpåsar istället för fruktkorg?\n\nBåda alternativen har sina fördelar. Här är situationer där fruktpåsar kan vara det bättre valet:\n\n### 1. Hybridkontor\n\nNär inte alla är på kontoret samtidigt undviker ni svinn med individuella påsar. Varje medarbetare som är på plats får sin egen frukt.\n\n### 2. Flera våningsplan\n\nIstället för att samla all frukt på ett ställe kan fruktpåsar distribueras till olika avdelningar och våningar.\n\n### 3. Möten och konferenser\n\nFruktpåsar är perfekta att ställa fram vid möten, workshops och konferenser som ett hälsosamt alternativ till kakor.\n\n### 4. Hygien\n\nVarje medarbetare hanterar bara sin egen frukt – en fördel som många uppskattar.\n\n## Jämförelse: Fruktpåse vs Fruktkorg\n\n| | Fruktpåse | Fruktkorg |\n|------|-----------|------------|\n| Format | Individuell portion | Gemensam skål/korg |\n| Bäst för | Hybrid, flera avd. | Samlat kontor |\n| Svinn | Minimalt | Kan uppstå |\n| Pris per person | Från 15 kr | Från 12 kr |\n| Flexibilitet | Hög – beställ antal | Medium |\n\n## Så beställer ni fruktpåsar\n\n1. **Välj antal** – Beställ det antal påsar ni behöver per vecka\n2. **Välj leveransdag** – Vi levererar den dag som passar er bäst\n3. **Vi levererar** – Fruktpåsarna levereras direkt till ert kontor\n\n**Fraktfritt i Stockholm, Södertälje och Uppsala.**\n\n[Se våra fruktpåsar](/produkter)\n\n## Kombinera med andra produkter\n\nVåra kunder kombinerar ofta fruktpåsar med:\n\n- **Kaffe och te** till fikarummet\n- **Nötmix och snacks** som komplement\n- **Smoothie-ingredienser** för det hälsomedvetna kontoret\n\n[Se hela sortimentet](/produkter)\n\n## Prova gratis\n\nVi erbjuder en **kostnadsfri provleverans** av fruktpåsar. Testa och se hur det fungerar för just ert kontor.\n\n[Beställ gratis provkorg](/provkorg)\n\n## Kontakta oss\n\nHar ni frågor om fruktpåsar eller vill ha en skräddarsydd offert? Vi hjälper er gärna.\n\n- Ring: [010-183 98 36](tel:010-1839836)\n- E-post: [info@vitaminkorgen.se](mailto:info@vitaminkorgen.se)\n- [Begär offert](/kontakt)'
),
(
  'Hållbar kontorsfrukt – Så minskar ni matsvinn med rätt fruktleverans',
  'hallbar-kontorsfrukt-minska-matsvinn',
  'tips',
  'Vitaminkorgen',
  'Så väljer ni en hållbar fruktleverans till kontoret och minskar matsvinn. Tips för miljömedvetna företag som vill göra skillnad med sin fruktkorg.',
  true,
  '2026-04-13T08:00:00Z',
  E'## Hållbar kontorsfrukt – Minska matsvinn och gör skillnad\n\nHållbarhet är inte längre ett val – det är en förväntan. Allt fler företag i Stockholm vill göra miljömedvetna val, och fruktleveransen till kontoret är ett enkelt ställe att börja. Men hur väljer man en **hållbar fruktleverans** som faktiskt gör skillnad?\n\n## Matsvinnet – ett dolt problem\n\nVisste ni att **en tredjedel av all mat som produceras i världen slängs**? På kontor är frukt ofta en av de saker som riskerar att bli över, särskilt om man beställer för mycket eller om frukten inte håller tillräckligt hög kvalitet.\n\n### Vanliga orsaker till fruktsvinn på kontor\n\n- Fel mängd – för stora beställningar i förhållande till antal medarbetare\n- Dålig kvalitet – omogna eller skadade frukter som ingen vill äta\n- Fel tidpunkt – leverans på fel dag gör att frukten hinner bli gammal\n- Bristande variation – samma frukt varje vecka tröttnar folk på\n\n## Så minimerar Vitaminkorgen matsvinn\n\nVi har byggt hela vår leveranskedja kring att **minimera svinn och maximera färskhet**:\n\n### 1. Rätt mängd varje gång\n\nVi hjälper er att beräkna exakt hur mycket frukt ert kontor behöver baserat på antal medarbetare och närvaro. Jobbar ni hybrid? Då anpassar vi leveransen.\n\n### 2. Dagsfärsk kvalitet\n\nAll frukt packas **samma dag som den levereras**. Vi handplockar varje frukt och kontrollerar kvaliteten – det betyder att frukten håller längre och att mer äts upp.\n\n### 3. Flexibla leveranser\n\nNi kan enkelt **pausa, justera eller ändra** er beställning via kundportalen. Semester? Konferensdag? Inga problem – ni betalar bara för det ni får.\n\n### 4. Säsongsbaserat innehåll\n\nGenom att använda **säsongens frukter** minskar vi transporterna och får bättre kvalitet. Svensk frukt prioriteras under säsong.\n\n## Tips: Minska ert fruktsvinn\n\nOavsett vilken leverantör ni väljer kan dessa tips hjälpa:\n\n- **Börja med mindre mängd** och öka vid behov\n- **Välj fruktpåsar** om ni har hybridarbete – då får bara närvarande medarbetare frukt\n- **Placera frukten synligt** – frukt som syns äts oftare\n- **Kommunicera** – berätta för medarbetarna att det finns frukt\n- **Återkoppla till leverantören** – säg till om det blir mycket över\n\n## Miljösmarta förpackningar\n\nVi använder **återanvändbara backar** för våra fruktleveranser. Inga engångskartonger, ingen onödig plast. Backarna hämtas vid nästa leverans och återanvänds.\n\n## Lokalt och kort leveranskedja\n\nVitaminkorgen arbetar med **lokala grossister** i Stockholmsområdet, vilket innebär:\n\n- Kortare transporter = lägre koldioxidutsläpp\n- Fräschare frukt som håller längre\n- Stöd till lokal ekonomi\n\n## Frukt som CSR-initiativ\n\nMånga av våra kunder använder sin **fruktkorg som en del av sitt hållbarhetsarbete**. En hållbar fruktleverans kan ingå i er CSR-rapport och visa medarbetare, kunder och partners att ni tar ansvar.\n\n### Siffror ni kan rapportera\n\n- Antal portioner hälsosam frukt per år\n- Minskat svinn genom anpassade leveranser\n- Lokala inköp och korta transportvägar\n\n## Kom igång med hållbar fruktleverans\n\nVill ni göra en miljösmart investering i medarbetarnas hälsa? Vi hjälper er att hitta rätt lösning.\n\n- [Beställ en gratis provkorg](/provkorg)\n- [Se våra fruktkorgar](/produkter)\n- Ring: [010-183 98 36](tel:010-1839836)\n\n**Vitaminkorgen – Hållbar fruktleverans till kontor i Stockholm sedan 2021.**'
);